using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: DataRow (using double inputs, cast to decimal) ──────

    [DataTestMethod]
    [DataRow(10.0, 1, 0.0, 10.0, DisplayName = "Single item, no tax")]
    [DataRow(10.0, 5, 0.0, 50.0, DisplayName = "Multiple items, no tax")]
    [DataRow(25.0, 2, 0.10, 55.0, DisplayName = "Two items at 10% tax")]
    [DataRow(0.0, 10, 0.20, 0.0, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.15, 0.0, DisplayName = "Zero quantity")]
    [DataRow(100.0, 1, 1.0, 200.0, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithDataRow_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal(
            (decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData (supports decimal natively) ─────────────

    private static IEnumerable<object[]> CalculateTotalCases
    {
        get
        {
            yield return [19.99m, 3, 0.08m, 64.7676m, "Fractional price with 8% tax"];
            yield return [0.01m, 1, 0.0m, 0.01m, "Minimum non-zero price"];
            yield return [999.99m, 100, 0.25m, 124998.75m, "Large order with 25% tax"];
            yield return [49.95m, 1, 0.0725m, 53.571375m, "Typical US sales tax (7.25%)"];
        }
    }

    [DataTestMethod]
    [DynamicData(nameof(CalculateTotalCases))]
    public void CalculateTotal_WithDynamicData_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate,
        decimal expected, string scenario)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    // ── CalculateTotal: invalid inputs ──────────────────────────────────────

    [DataTestMethod]
    [DataRow(-1.0, 1, 0.1, "unitPrice", DisplayName = "Negative unit price")]
    [DataRow(10.0, -1, 0.1, "quantity", DisplayName = "Negative quantity")]
    [DataRow(10.0, 1, -0.1, "taxRate", DisplayName = "Negative tax rate")]
    [DataRow(10.0, 1, 1.1, "taxRate", DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidInput_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(
                (decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // ── ApplyDiscount: DataRow ──────────────────────────────────────────────

    [DataTestMethod]
    [DataRow(100.0, 0.0, 100.0, DisplayName = "No discount")]
    [DataRow(100.0, 50.0, 50.0, DisplayName = "50% discount")]
    [DataRow(100.0, 100.0, 0.0, DisplayName = "Full discount")]
    [DataRow(200.0, 25.0, 150.0, DisplayName = "25% off $200")]
    [DataRow(0.0, 50.0, 0.0, DisplayName = "Discount on zero price")]
    public void ApplyDiscount_WithDataRow_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount(
            (decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── ApplyDiscount: DynamicData (method source) ──────────────────────────

    private static IEnumerable<object[]> GetDiscountEdgeCases()
    {
        yield return [79.99m, 15m, 67.9915m, "Fractional result"];
        yield return [0.01m, 10m, 0.009m, "Small price, small discount"];
        yield return [9999.99m, 99.99m, 0.999999m, "Near-total discount"];
    }

    [DataTestMethod]
    [DynamicData(nameof(GetDiscountEdgeCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_WithDynamicData_ReturnsExpected(
        decimal price, decimal discountPercent,
        decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    // ── ApplyDiscount: invalid inputs ───────────────────────────────────────

    [DataTestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(100.01, DisplayName = "Discount exceeds 100%")]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(
        double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // ── FormatPrice: DataRow ────────────────────────────────────────────────

    [DataTestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default USD")]
    [DataRow(1000.0, "€", "€1000.00", DisplayName = "Euro symbol")]
    [DataRow(0.0, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(5.1, "£", "£5.10", DisplayName = "Pads to two decimals")]
    public void FormatPrice_WithDataRow_ReturnsExpected(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

